import { useState } from 'react'
import { agents } from '../data/agents'
import AgentCard from './AgentCard'
import AgentDetail from './AgentDetail'
import OrgChart from './OrgChart'
import ProgressSidebar from './ProgressSidebar'

export default function Dashboard() {
  const [selectedId, setSelectedId] = useState<string | null>(null)
  const selectedAgent = agents.find((a) => a.id === selectedId)

  return (
    <div className="max-w-7xl mx-auto px-6 py-8">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Agent Cards */}
        <div className="lg:col-span-2 space-y-4">
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-2">
            エージェント一覧
          </h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {agents.map((agent) => (
              <AgentCard
                key={agent.id}
                agent={agent}
                isSelected={selectedId === agent.id}
                onClick={() =>
                  setSelectedId(selectedId === agent.id ? null : agent.id)
                }
              />
            ))}
          </div>
        </div>

        {/* Right: Progress + Org Chart */}
        <div className="space-y-4">
          <ProgressSidebar />
          <OrgChart />
          <div className="rounded-xl border border-slate-700/50 bg-slate-800/30 p-5">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">
              データフォルダ
            </h3>
            <div className="space-y-2 text-xs text-slate-400 font-mono">
              {[
                { icon: '📊', path: 'context/market/' },
                { icon: '🎯', path: 'context/strategy/' },
                { icon: '📢', path: 'context/communication/' },
                { icon: '🤝', path: 'context/sales/' },
                { icon: '⚙️', path: 'context/tech/' },
                { icon: '📝', path: 'context/memos/' },
              ].map((item) => (
                <div key={item.path} className="flex items-center gap-2">
                  <span>{item.icon}</span>
                  <span>{item.path}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Detail Panel */}
      {selectedAgent && (
        <div className="mt-8">
          <AgentDetail agent={selectedAgent} />
        </div>
      )}
    </div>
  )
}

import { agents } from '../data/agents'
import { useProgress } from '../hooks/useProgress'

const colorMap: Record<string, { dot: string; bar: string; text: string }> = {
  cmo: { dot: 'bg-blue-400', bar: 'bg-blue-500', text: 'text-blue-400' },
  planner: { dot: 'bg-violet-400', bar: 'bg-violet-500', text: 'text-violet-400' },
  researcher: { dot: 'bg-emerald-400', bar: 'bg-emerald-500', text: 'text-emerald-400' },
  cso: { dot: 'bg-amber-400', bar: 'bg-amber-500', text: 'text-amber-400' },
  cto: { dot: 'bg-red-400', bar: 'bg-red-500', text: 'text-red-400' },
}

const statusIcon: Record<string, string> = {
  pending: '○',
  in_progress: '◉',
  done: '✓',
}

const statusColor: Record<string, string> = {
  pending: 'text-slate-500',
  in_progress: 'text-yellow-400 animate-pulse',
  done: 'text-green-400',
}

export default function ProgressSidebar() {
  const agentProgress = useProgress(5000)

  if (agentProgress.length === 0) {
    return (
      <div className="rounded-xl border border-slate-700/50 bg-slate-800/30 p-5">
        <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">
          エージェント進捗
        </h3>
        <p className="text-xs text-slate-500 animate-pulse">読み込み中...</p>
      </div>
    )
  }

  const totalDone = agentProgress.reduce(
    (sum, ap) => sum + ap.tasks.filter((t) => t.status === 'done').length,
    0
  )
  const totalTasks = agentProgress.reduce((sum, ap) => sum + ap.tasks.length, 0)
  const totalPct = totalTasks > 0 ? Math.round((totalDone / totalTasks) * 100) : 0

  return (
    <div className="rounded-xl border border-slate-700/50 bg-slate-800/30 p-5">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
          エージェント進捗
        </h3>
        <span className="text-[10px] px-2 py-0.5 rounded-full bg-green-500/20 text-green-400 font-medium">
          LIVE
        </span>
      </div>
      <div className="space-y-5">
        {agentProgress.map((ap) => {
          const agent = agents.find((a) => a.id === ap.agentId)
          const c = colorMap[ap.agentId] ?? colorMap.cmo
          const doneCount = ap.tasks.filter((t) => t.status === 'done').length
          const total = ap.tasks.length
          const pct = total > 0 ? Math.round((doneCount / total) * 100) : 0

          return (
            <div key={ap.agentId}>
              <div className="flex items-center justify-between mb-1.5">
                <div className="flex items-center gap-2">
                  <span className="text-base">{agent?.emoji}</span>
                  <span className={`text-xs font-bold ${c.text}`}>{agent?.title}</span>
                </div>
                <span className="text-[10px] text-slate-500 font-mono">
                  {doneCount}/{total}
                </span>
              </div>

              <div className="w-full h-1.5 bg-slate-700 rounded-full mb-2">
                <div
                  className={`h-1.5 rounded-full transition-all duration-500 ${c.bar}`}
                  style={{ width: `${pct}%` }}
                />
              </div>

              <div className="space-y-1 pl-1">
                {ap.tasks.map((task) => (
                  <div key={task.file} className="flex items-center gap-2">
                    <span className={`text-xs ${statusColor[task.status]}`}>
                      {statusIcon[task.status]}
                    </span>
                    <span
                      className={`text-[11px] ${
                        task.status === 'done' ? 'text-slate-500 line-through' : 'text-slate-400'
                      }`}
                    >
                      {task.label}
                    </span>
                    {task.status === 'in_progress' && (
                      <span className="text-[9px] px-1.5 py-0.5 rounded bg-yellow-500/20 text-yellow-400 font-medium">
                        作業中
                      </span>
                    )}
                    {task.status === 'done' && (
                      <span className="text-[9px] px-1.5 py-0.5 rounded bg-green-500/20 text-green-400 font-medium">
                        完了
                      </span>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )
        })}
      </div>

      <div className="mt-5 pt-4 border-t border-slate-700/50">
        <div className="flex items-center justify-between">
          <span className="text-xs text-slate-400">全体進捗</span>
          <span className="text-xs font-mono text-slate-300">
            {totalDone}/{totalTasks} タスク
          </span>
        </div>
        <div className="w-full h-2 bg-slate-700 rounded-full mt-2">
          <div
            className="h-2 rounded-full bg-gradient-to-r from-blue-500 via-violet-500 to-emerald-500 transition-all duration-500"
            style={{ width: `${totalPct}%` }}
          />
        </div>
      </div>
    </div>
  )
}

