import { useState, useEffect } from 'react'
import type { TaskProgress } from '../data/progress'

export function useProgress(intervalMs = 5000): TaskProgress[] {
  const [data, setData] = useState<TaskProgress[]>([])

  useEffect(() => {
    const fetchProgress = async () => {
      try {
        const res = await fetch('/api/progress')
        if (res.ok) {
          setData(await res.json())
        }
      } catch {
        // silently retry next interval
      }
    }

    fetchProgress()
    const id = setInterval(fetchProgress, intervalMs)
    return () => clearInterval(id)
  }, [intervalMs])

  return data
}

export interface TaskProgress {
  agentId: string
  tasks: {
    label: string
    file: string
    status: 'pending' | 'in_progress' | 'done'
  }[]
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import tailwindcss from '@tailwindcss/vite'
import fs from 'fs'
import path from 'path'

const CONTEXT_ROOT = path.resolve(process.env.USERPROFILE || '', '.claude/context')

const FILE_MAP = [
  { agentId: 'cmo', label: 'ブランド戦略', file: 'strategy/brand-strategy.md' },
  { agentId: 'cmo', label: 'KPI目標設定', file: 'strategy/kpi-targets.md' },
  { agentId: 'cmo', label: '年間計画', file: 'strategy/annual-plan.md' },
  { agentId: 'planner', label: '統合コミュプラン', file: 'communication/integrated-plan.md' },
  { agentId: 'planner', label: 'CRM施策', file: 'communication/crm-plan.md' },
  { agentId: 'planner', label: 'メディア・SNS', file: 'communication/media-sns.md' },
  { agentId: 'researcher', label: '市場トレンド', file: 'market/market-trends.md' },
  { agentId: 'researcher', label: '競合分析', file: 'market/competitors.md' },
  { agentId: 'researcher', label: '口コミ収集', file: 'market/reviews-wom.md' },
  { agentId: 'cso', label: '顧客インサイト', file: 'sales/customer-insights.md' },
  { agentId: 'cso', label: '営業戦術', file: 'sales/sales-tactics.md' },
  { agentId: 'cto', label: 'プロンプト集', file: 'tech/prompts.md' },
  { agentId: 'cto', label: 'Claude Code Tips', file: 'tech/claude-code-tips.md' },
  { agentId: 'cmo', label: 'レビュー: 戦略', file: 'reviews/review-strategy.md' },
  { agentId: 'planner', label: 'レビュー: コミュ', file: 'reviews/review-communication.md' },
  { agentId: 'researcher', label: 'レビュー: 市場/営業', file: 'reviews/review-market-sales.md' },
  { agentId: 'cto', label: 'レビュー: 技術', file: 'reviews/review-tech.md' },
]

function isTemplate(content: string): boolean {
  if (!content || content.trim().length < 200) return true
  const markers = ['<!-- ここに']
  return markers.some(m => content.includes(m))
}

function getProgress() {
  const agentMap: Record<string, { agentId: string; tasks: { label: string; file: string; status: string }[] }> = {}

  for (const entry of FILE_MAP) {
    if (!agentMap[entry.agentId]) {
      agentMap[entry.agentId] = { agentId: entry.agentId, tasks: [] }
    }
    const filePath = path.join(CONTEXT_ROOT, entry.file)
    let status = 'pending'
    try {
      const content = fs.readFileSync(filePath, 'utf-8')
      status = isTemplate(content) ? 'in_progress' : 'done'
    } catch {
      status = 'pending'
    }
    agentMap[entry.agentId].tasks.push({ label: entry.label, file: entry.file, status })
  }
  return Object.values(agentMap)
}

export default defineConfig({
  plugins: [
    react(),
    tailwindcss(),
    {
      name: 'progress-api',
      configureServer(server) {
        server.middlewares.use('/api/progress', (_req, res) => {
          res.setHeader('Content-Type', 'application/json')
          res.end(JSON.stringify(getProgress()))
        })
      },
    },
  ],
})

