export default function ScheduledTaskCard() {
  return (
    <div className="mt-10">
      <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">
        スケジュールタスク
      </h2>
      <div className="rounded-xl border border-slate-700/50 bg-slate-800/30 p-5">
        {/* ヘッダー */}
        <div className="flex items-start justify-between mb-5">
          <div>
            <div className="flex items-center gap-2">
              <span className="text-base">⏰</span>
              <span className="text-sm font-bold text-slate-200">SHUWAN 日次PDCA</span>
            </div>
            <div className="text-[10px] text-slate-500 font-mono mt-0.5 ml-6">
              scheduled-tasks/shuwan-daily-pdca/SKILL.md
            </div>
          </div>
          <span className="text-[10px] px-2 py-0.5 rounded-full bg-emerald-500/15 text-emerald-400 border border-emerald-500/30">
            毎日実行
          </span>
        </div>

        {/* ステップ一覧 */}
        <div className="space-y-3">
          {steps.map((step, i) => (
            <div key={step.num} className="flex gap-3">
              {/* ステップ番号 + 縦線 */}
              <div className="flex flex-col items-center">
                <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold shrink-0 ${
