import { useState } from 'react'
import { agents } from '../data/agents'
import AgentCard from './AgentCard'
import AgentDetail from './AgentDetail'
import AgentDefinitionTable from './AgentDefinitionTable'
import OrgChart from './OrgChart'
import ProgressSidebar from './ProgressSidebar'

export default function Dashboard() {
  const [selectedId, setSelectedId] = useState<string | null>(null)
  const selectedAgent = agents.find((a) => a.id === selectedId)

  return (
    <div className="max-w-7xl mx-auto px-6 py-8">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Agent Cards */}
        <div className="lg:col-span-2 space-y-4">
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-2">
            エージェント一覧
          </h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {agents.map((agent) => (
              <AgentCard
                key={agent.id}
                agent={agent}
                isSelected={selectedId === agent.id}
                onClick={() =>
                  setSelectedId(selectedId === agent.id ? null : agent.id)
                }
              />
            ))}
          </div>
        </div>

        {/* Right: Progress + Org Chart */}
        <div className="space-y-4">
          <ProgressSidebar />
          <OrgChart />
          <div className="rounded-xl border border-slate-700/50 bg-slate-800/30 p-5">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">
              データフォルダ
            </h3>
            <div className="space-y-2 text-xs text-slate-400 font-mono">
              {[
                { icon: '📊', path: 'context/market/' },
                { icon: '🎯', path: 'context/strategy/' },
                { icon: '📢', path: 'context/communication/' },
                { icon: '🤝', path: 'context/sales/' },
                { icon: '⚙️', path: 'context/tech/' },
                { icon: '📝', path: 'context/memos/' },
              ].map((item) => (
                <div key={item.path} className="flex items-center gap-2">
                  <span>{item.icon}</span>
                  <span>{item.path}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Detail Panel */}
      {selectedAgent && (
        <div className="mt-8">
          <AgentDetail agent={selectedAgent} />
        </div>
      )}

      {/* Agent Definition Table - always visible */}
      <AgentDefinitionTable />
    </div>
  )
}

